<script>
export default {
    props: [
        'card',
    ],
    data: () => {
        return {
            textAlign: '',
        }
    },
    mounted() {
        let lang = Nova.config.local ;
        lang == 'en' ? this.textAlign = 'text-left' : this.textAlign = 'text-right' ;
    },
    methods: {
        goTo(type) {

          if(type === 'roles'){
            this.$router.push('/resources/' + type)
          }else{
            this.$router.push('/resources/' + type)
          }
        },
        gotoCustomComponent(name){
          this.$router.push({name : 'units.' + name})
        }
    }
}
</script>

